        for (uint16_t i = 0; i < (uint16_t)(validRows); ++i) {
            for (uint16_t j = 0; j < (uint16_t)fullRepeats; ++j) {
                vlds(vreg0_PU, src0Ptr, ElementsPerRepeat, NORM, POST_UPDATE);
                vlds(vreg1_PU, src1Ptr, ElementsPerRepeat, NORM, POST_UPDATE);
