[aicore] inline __attribute__((always_inline)) __attribute__((visibility("default"))) bool ApplySatMode(SaturationMode satMode)
{
    uint64_t originalCtrl = get_ctrl();
    bool originalSatMode = (originalCtrl & (1ULL << SAT_MODE_BIT)) == 0;
    if (satMode == SaturationMode::OFF) {
        set_ctrl(sbitset1(get_ctrl(), SAT_MODE_BIT));
    } else {
        set_ctrl(sbitset0(get_ctrl(), SAT_MODE_BIT));
    }
    return originalSatMode;
}

[aicore] inline __attribute__((always_inline)) __attribute__((visibility("default"))) void RestoreSatMode(bool originalSatMode)
{
    if (originalSatMode) {
        set_ctrl(sbitset0(get_ctrl(), SAT_MODE_BIT));
    } else {
        set_ctrl(sbitset1(get_ctrl(), SAT_MODE_BIT));
    }
}
