        } else {
            return size;
        }
    }

    template <uint64_t stride>
    [aicore] inline __attribute__((always_inline)) static constexpr uint64_t TransStride()
    {
        if constexpr (isB8) {
            return stride / sizeof(TransType);
        } else {
