    int transValidCol = TRANS::TransSize(validCol);
    T *dstPtr = ( T *)__cce_get_tile_ptr(dst);
    T *srcPtr = ( T *)__cce_get_tile_ptr(src);

    constexpr int dstStride = TRANS::template TransStride<TileDataDst::RowStride>();
