        set_mask_norm();
        set_vector_mask(-1, -1);
    } else {

        TRowReduceInstr<TRowSumOp<T>, T, TileDataOut, TileDataIn, TileDataTmp>(dst, src, tmp, validCol, validRow);
    }
}

