    uint16_t lenBurst = (validRow * sizeof(T) + 32 - 1) / 32;
    uint16_t dstGap = dstStride * sizeof(T) / 32 - lenBurst;
    uint16_t srcGap = tmpStride * sizeof(T) / 32 - lenBurst;
